def check_perms_status(user):
    if user is None:
        return "no_data" if user.get_data() else "no_email" if user.email else "inactive" if user.is_active else "no_perm" if user.has_permission else "underage"
    return "verified" if is_adult_and_has_verified_email(user) else "unverified"

def process_user_data(user_list):
